const Q_BIOLOGY_2002=[{"id": "objective>Biology>2002>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An amoeba and an unlaid chicken egg are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">animal tissues</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organelles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">single cells </div>", "<div style=\"font-family:Cambria;font-size:17px;\">organisms</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An amoeba and an unlaid chicken egg are both single cells. An amoeba is a single-celled organism that moves by changing shape. It is one of the simplest creatures that exists. An egg, before it is laid, is also a single cell. It is the largest single cell that can be seen without the aid of a microscope.</div>", "topic": "LIVING ORGANISMS : LEVEL OF ORGANIZATION"}, {"id": "objective>Biology>2002>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In corms, food is usually stored in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">leaves   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stems    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">roots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buds</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In corms, food is usually stored in the stems. Corms are short, vertical, swollen underground plant stems that serve as storage organs used by some plants to survive winter or other adverse conditions such as summer drought and heat.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2002>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The animals that move by means of Flagella include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chlamydomonas and Euglena</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Planaria and Amoeba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amoeba and Hydra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Paramecium and Planaria</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Flagella are whip-like structures that allow cells to move. They are found in both prokaryotic and eukaryotic cells. Chlamydomonas and Euglena are examples of organisms that use flagella for movement.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : PROTISTA"}, {"id": "objective>Biology>2002>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The structures found only in plant cell are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cell membranes and cytoplasm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chromatin and nucleolus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell wall and chloroplast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell membrane and lysosome</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cell wall and chloroplast are structures found only in plant cells. The cell wall provides structural support and protection, while the chloroplast is involved in photosynthesis, the process by which plants convert light energy into chemical energy.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2002>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A flower that has both stamens and pistil is said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">staminate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pistillate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">imperfect</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A flower that has both stamens (male reproductive organs) and pistils (female reproductive organs) is said to be perfect. This means it has the ability to self-pollinate, although cross-pollination may still occur.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2002>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When oil is poured into the breeding site of mosquitoes, it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deprives the larvae of water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kills the adults</div>", "<div style=\"font-family:Cambria;font-size:17px;\">suffocates the pupae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slows down egg development</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When oil is poured into the breeding site of mosquitoes, it suffocates the pupae. This is because the oil forms a thin layer on the surface of the water, preventing oxygen from reaching the mosquito larvae and pupae that breathe through spiracles located on their abdomens. This lack of oxygen suffocates the pupae.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2002>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The correct evolutionary sequence of the organisms represented is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I → III → II → IV </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II → III → IV → I </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III → II → I → IV </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV → II → III → I</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct evolutionary sequence of the organisms represented is IV → II → III → I.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2002>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> Ovoviparity is the type of fertilization exhibited by the organism labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II        </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III      </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ovoviparity is exhibited by toads , there  is no placenta connection and the young are nourished by egg yolk.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2002>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> In the diagram, the hawk is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an omnivore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a primary consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a tertiary consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a scavenger</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A tertiary consumer is a carnivore at the topmost level in a food chain that feeds on other carnivores.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>2002>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Examples of competitors are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lizard and mouse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">snake and lizard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">grasshopper and mouse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rabbit and snake</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Grasshopper and mouse competitors because they both feed on vegetation in the food web.</div>", "topic": "ADAPTATION FOR SURVIVAL : COMPETITION"}, {"id": "objective>Biology>2002>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the adaptations to life on trees by a monkey is its possession of digits which are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">extensible</div>", "<div style=\"font-family:Cambria;font-size:17px;\">big</div>", "<div style=\"font-family:Cambria;font-size:17px;\">opposable \t</div>", "<div style=\"font-family:Cambria;font-size:17px;\">long</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the adaptations to life on trees by a monkey is its possession of opposable digits. Opposable digits, usually thumbs, allow monkeys to grasp and manipulate objects, including tree branches, effectively. This is a crucial adaptation for life in the trees, as it enables them to move around efficiently and securely.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2002>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The community of plants in which the same species occur from year to year is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">annual species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pioneer vegetation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perennial species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">climax vegetation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The community of plants in which the same species occur from year to year is the climax vegetation. Climax vegetation is the final stage of succession, remaining relatively unchanged until destroyed by an event such as fire or human interference. It is a stable community that is in equilibrium with the environment.</div>", "topic": "THE ECOLOGY OF POPULATIONS : ECOLOGICAL SUCCESSION"}, {"id": "objective>Biology>2002>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most common means of transmitting the Acquired Immune Deficiency Syndrome (AIDS) is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">from mother to child</div>", "<div style=\"font-family:Cambria;font-size:17px;\">through blood transfusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">through sexual intercourse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">through the sharing of needles</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most common means of transmitting the Acquired Immune Deficiency Syndrome (AIDS) is through sexual intercourse. AIDS is primarily transmitted through unprotected sexual intercourse with an infected person. It can also be transmitted through sharing of needles, blood transfusion, and from an infected mother to her child during childbirth or breastfeeding, but these are less common.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2002>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plants tend to prevent overcrowding by means of efficient</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water uptake</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seed germination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pollination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seed dispersal</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plants tend to prevent overcrowding by means of efficient seed dispersal. Seed dispersal is the movement or transport of seeds away from the parent plant. Plants have very limited mobility and consequently rely upon a variety of dispersal vectors to transport their propagules, including both abiotic vectors such as the wind and living (biotic) vectors like birds. Seed dispersal is likely to have several benefits for plant species. First, seed survival is often higher away from the parent plant. This higher survival may result from the actions of density-dependent mortality agents, which often kill more seeds at high densities.</div>", "topic": "THE ECOLOGY OF POPULATIONS : POPULATION DENSITY AND OVERCROWDING"}, {"id": "objective>Biology>2002>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The physical and climatic factors of a region primarily determine the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kinds of animal inhabiting the area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">types of plants found in the area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nature of the soil in that region</div>", "<div style=\"font-family:Cambria;font-size:17px;\">community of organisms in the region</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The physical and climatic factors of a region primarily determine the community of organisms in the region. The physical factors like temperature, humidity, rainfall and soil type in a region determine what types of plants and animals can survive there. These organisms together form a community. For example, cacti, snakes and scorpions are found in deserts due to the hot and dry climate, while polar bears and seals are found in polar regions due to the cold climate.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2002>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A step in the movement of energy through an ecosystem is a description that best fits the term</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">food chain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trophic level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pyramid of numbers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">food web</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A trophic level refers to a step in the movement of energy through an ecosystem. Energy moves up the food chain by passing through different trophic levels. For example, plants take up energy from the sun and are eaten by herbivores, which are then eaten by carnivores. Each of these stages represents a different trophic level.</div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>2002>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a field experiment, the frequency of water leaf  was observed to be 48 after 20 tosses of a 2m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> quadrant. What is the density of the plant in the field?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.2per m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.4per m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.8per m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.6per m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The density of a population in ecology is calculated as the number of individuals per unit area or volume. In this case, the frequency of water leaf was observed to be 48 after 20 tosses of a 2m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> quadrant. Therefore, the density of the plant in the field is 48/40 = 1.2 per m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>.</div>", "topic": "THE ECOLOGY OF POPULATIONS : POPULATION DENSITY AND OVERCROWDING"}, {"id": "objective>Biology>2002>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The supporting tissue of xylem is most poorly developed in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mangrove swamp plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">grassland plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">submerged water plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">desert plants</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The supporting tissue of xylem is most poorly developed in submerged water plants. This is because these plants live in water and therefore do not need to transport water from the roots to other parts of the plant as land plants do. The xylem, which is responsible for this transportation, is thus not as developed.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2002>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The addition of lime to clayey soil serves to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aid water retention</div>", "<div style=\"font-family:Cambria;font-size:17px;\">close up the texture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent water-logging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improve capillary action</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The addition of lime to clayey soil serves to prevent water-logging. Clayey soil has small, tightly packed particles that can hold water, but this can also lead to water-logging. Lime helps to break up these particles, improving drainage and preventing water-logging.</div>", "topic": "SOIL : SOIL FERTILITY"}, {"id": "objective>Biology>2002>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The excessive use of agro-chemicals could lead to the pollution of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the lithosphere </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the atmosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fresh water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">space</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The excessive use of agro-chemicals could lead to the pollution of fresh water. Agro-chemicals, such as fertilizers and pesticides, can run off from agricultural land into rivers and lakes, causing water pollution. This can harm aquatic life and make the water unsafe for human consumption.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>2002>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a population study using the transect method, a student is likely to record the highest number of species in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a tropical rain forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a guinea savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a sahel savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an estuarine swamp</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a population study using the transect method, a student is likely to record the highest number of species in a guinea savanna. </div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2002>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In his theory of evolution, Darwin implied that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the struggle for existence among living organisms is sporadic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the most successful organisms are those that best adapt to their environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organs of the body which are not regularly used by an organism will disappear</div>", "<div style=\"font-family:Cambria;font-size:17px;\">any traits acquired by an organism during its lifetime can be passed on to its offspring</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Darwin's theory of evolution, also known as Darwinism, implies that the most successful organisms are those that best adapt to their environment. This is the principle of natural selection, where individuals with traits that increase their probability of survival will have more opportunities to reproduce, and their offspring will also benefit from these advantageous traits.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2002>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The carnassial teeth of a carnivorous animal consist of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">last upper premolar and the first lower molar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">last upper molar and the last lower molar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">first upper premolar and the first lower molar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">first upper molar and the first lower molar</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The carnassial teeth of a carnivorous animal consist of the last upper premolar and the first lower molar. Carnassial teeth are modified molars (and in the case of carnivorans, premolars) which are adapted in certain mammals to allow for the shearing (rather than tearing) of flesh to permit the more efficient consumption of meat.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2002>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A feature of the caste systems of bees and termites is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the workers are sterile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the kings are bigger than the queens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only the worker perform duties </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nuptial flight is performed by all members</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the caste systems of bees and termites, the workers are typically sterile. This is a feature of eusociality, a high level of organization of animal sociality, where the workers forego their own reproduction to care for the offspring of others (usually the queen).</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2002>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The structure that is common in the embryos of mammals, amphibians, birds, fishes and reptiles and which is an evidence of their common ancestry is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">eye</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chorion    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">allantois</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gill-slits</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gill-slits are a structure that is common in the embryos of mammals, amphibians, birds, fishes and reptiles. This is an evidence of their common ancestry. Gill-slits are the rudimentary structures that are present in the embryos of these animals and are indicative of their aquatic ancestry. They later develop into different structures in different animals as they evolve.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2002>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Animals aestivate when the environment in which they live becomes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hot and dry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cold and wet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warm and humid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">windy and snowy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Animals aestivate when the environment in which they live becomes hot and dry. Aestivation, or estivation, is a state of animal dormancy, similar to hibernation, characterized by inactivity and a lowered metabolic rate, that is entered in response to high temperatures and arid conditions. It takes place during times of heat and dryness, the hot dry season, which are often the summer months.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2002>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Birds which are large with long straight pointed beaks, long necks and long legs are likely to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">insect eaters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fish catchers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nectar feeders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fruit eaters</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Birds which are large with long straight pointed beaks, long necks and long legs are likely to be fish catchers. These physical characteristics are adaptations that help the bird to catch fish. The long straight pointed beak is used to spear the fish, the long neck helps in reaching into the water to catch the fish and the long legs are used for wading in the water.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2002>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Examples of organisms in which extracellular digestion occurs are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fungus, Loranthus and housefly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rhizopus, sponges and earthworm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Round worm, tapeworm and hydra </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rhizopus, housefly and hydra</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Extracellular digestion is the process where digestion takes place outside the cells in a digestive cavity. Fungi, such as Rhizopus, perform extracellular digestion by secreting enzymes into their environment. Houseflies also perform extracellular digestion by regurgitating digestive enzymes onto their food and then absorbing the nutrients. Hydra perform extracellular digestion by releasing enzymes into their gastrovascular cavity.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2002>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mammalian erythrocytes differ from the leucocytes at maturity because the erythrocytes are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">discoid and nucleated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discoid and enucleated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amoeboid and nucleated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amoeboid and enucleated</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mammalian erythrocytes, also known as red blood cells, are discoid (disk-shaped) and enucleated (lack a nucleus at maturity). This is in contrast to leucocytes, or white blood cells, which are nucleated and can change shape.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2002>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of endoskeleton is characteristic of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">invertebrata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vertebrata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insecta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coelenterata</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Endoskeleton is an internal support structure of an animal, composed of mineralized tissue. Endoskeleton develops within the skin or in the deeper body tissues. The vertebrates (animals with a backbone, including mammals, birds, reptiles, amphibians, and fishes) possess an endoskeleton.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BONY FISH"}, {"id": "objective>Biology>2002>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The capture and digestion of insects by a pitcher plant is a special form of nutrition termed ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">autotrophic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heterotrophic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chemosynthetic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saprophytic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The capture and digestion of insects by a pitcher plant is a special form of nutrition termed heterotrophic. Heterotrophic nutrition is when an organism relies on organic substances for its nutrition because it cannot synthesize its own food. In this case, the pitcher plant, which is typically a photosynthetic plant, supplements its nutrition by capturing and digesting insects.</div>", "topic": "NUTRITION : MODES OF NUTRITION"}, {"id": "objective>Biology>2002>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  Use the diagram to answer this question. <br/>  <br/> Which of the following statements is correct about the experiment?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The flask must be of the conical type</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Caustic soda can be replaced with distilled water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The enclosed leaf will lose its green colour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The leaves outside the flask serve as control</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The leaves outside the flask serve as control is correct about the experiment</div>", "topic": "PHOTOSYNTHESIS"}, {"id": "objective>Biology>2002>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  Use the diagram to answer this question. <br/> The experimental set-up can be used to demonstrate that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">light is necessary for photosynthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen is necessary for photosynthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">photosynthesis occurs in the leaves of plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV)oxide is necessary for photosynthesis</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The experimental set-up can be used to demonstrate that carbon(IV)oxide is necessary for photosynthesis.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2002>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a marine fish was taken from the ocean and put in a tank of fresh water, it died after a short period because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the tank was too small compared to the large ocean</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the body cells of the fish swelled and burst as a result of the hypotonic fresh water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the body cells of the fish shrank as their sap was hypertonic to the fresh water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there was no food in the tank, so the fish starved.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a marine fish is taken from the ocean and put in a tank of fresh water, it dies after a short period because the body cells of the fish swelled and burst as a result of the hypotonic fresh water. This is due to osmosis, a process where water moves from an area of lower solute concentration (the fresh water) to an area of higher solute concentration (the body cells of the fish). The cells swell and can burst due to the influx of water.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2002>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pairs of organs is located in the anterior half of the mammalian body cavity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kidneys and lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heart and ovary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lungs and heart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kidneys and heart</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pair of organs located in the anterior half of the mammalian body cavity are the lungs and heart. The anterior half of the body cavity, also known as the thoracic cavity, houses the heart and lungs, among other structures.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2002>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mode of nutrition exhibited by a tapeworm is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">symbiotic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">saprophytic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parasitic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">holozoic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A tapeworm is a type of parasite that lives in the intestines of its host. Parasitic nutrition is when an organism lives on or in its host and causes harm to it. The tapeworm absorbs nutrients directly from the host's gut, hence it exhibits parasitic nutrition.</div>", "topic": "NUTRITION : MODES OF NUTRITION"}, {"id": "objective>Biology>2002>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organ located within the duodenal loop in the mammal is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">spleen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pancreas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gall bladder</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pancreas is located within the loop of the duodenum. The duodenum is the first part of the small intestine, and the pancreas is a gland organ that is part of the digestive and endocrine systems. It releases digestive enzymes into the duodenum to help with digestion and also produces insulin and other hormones.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2002>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following groups of fruits is the pericarp inseparable from the seed coat?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nut</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Follicle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cypsela</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Caryopsis</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a caryopsis, the pericarp (the part of a fruit formed from the ovary wall) is inseparable from the seed coat. This is typical of grains like corn, wheat, and rice. The other options, Nut, Follicle, and Cypsela, do not have this characteristic.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : SEED"}, {"id": "objective>Biology>2002>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A person that is obese must avoid meals containing</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carrots and oranges</div>", "<div style=\"font-family:Cambria;font-size:17px;\">margarine and butter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">beef and beans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rice and yam</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Obesity is a condition characterized by excessive body fat. It is often associated with a high intake of fats and sugars. Margarine and butter are high in fats and should be avoided by an obese person to prevent further weight gain. Carrots and oranges are fruits and vegetables that are low in fats and high in fiber, which is beneficial for weight loss. Beef and beans are sources of protein, which is essential for body functions and not necessarily linked to obesity. Rice and yam are carbohydrates, which provide energy for the body and are not directly linked to obesity.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2002>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Tissue respiration is important for the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">absorption of oxygen into the alveoli</div>", "<div style=\"font-family:Cambria;font-size:17px;\">release of carbon(IV)oxide into the lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">release of energy for the body use</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exhalation of carbon(IV)oxide from the lungs</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tissue respiration, also known as cellular respiration, is the process by which cells in the body convert glucose and oxygen into energy, carbon dioxide, and water. This energy is used to power various cellular processes. The absorption of oxygen into the alveoli and the release of carbon dioxide into the lungs are part of the respiratory process, not tissue respiration. The exhalation of carbon dioxide from the lungs is also part of the respiratory process, not tissue respiration.</div>", "topic": "RESPIRATION : AEROBIC RESPIRATION"}, {"id": "objective>Biology>2002>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question. <br/>  <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The function of absorption is performed by the structure labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It's function is absorption of nutrients. The part labelled II is the root hair. Root hairs increase the root's surface area, aiding in water and nutrient absorption, anchoring the plant in soil, and facilitating symbiotic relationships with soil microbes.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : ROOT"}, {"id": "objective>Biology>2002>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question. <br/>  <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The structure labelled I represents the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">phloem        </div>", "<div style=\"font-family:Cambria;font-size:17px;\">xylem    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cortex</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pericycle</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pericycle is a cylinder of parenchyma or sclerenchyma cells that lies just inside the endodermis and is the outer most part of the stele of plants. It strengthens the stem and provides protection for the vascular bundles.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : ROOT"}, {"id": "objective>Biology>2002>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The gland usually found in the position labelled I is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adrenal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">thyroid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pancreatic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pituitary</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the major endocrine gland, a pea-sized body attached to the base of the brain that is important in controlling growth and development and the functioning of the other endocrine glands.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2002>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The hormone secreted at IV serves to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">facilitate the development of facial hairs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raise the level of calcium ions in the blood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lower blood glucose level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make the body react to emergencies</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">IV is a sex hormone that facilitate the development of facial hairs.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2002>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To select and retain the desirable trait of large body size which a farmer has observed in his herd, the farmer needs to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">feed the animals in the herd with more food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cross-breed his animals with a different herd</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inbreed the animals in his herd</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent diseases in his herd</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The farmer needs to inbreed the animals in his herd. Inbreeding is the mating of organisms closely related by ancestry. This method is often used to retain desirable traits in a herd. By inbreeding, the farmer can increase the chances of the offspring inheriting the desirable trait of large body size.</div>", "topic": "HEREDITY : APPLICATION OF THE PRINCIPLES OF HEREDITY"}, {"id": "objective>Biology>2002>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a population of living things, the parameters of size, height, weight and colour are examples of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">discontinuous variations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continuous variations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">physiological variations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-heritable variations</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Size, height, weight, and colour are examples of continuous variations. Continuous variations are those that have a range of phenotypes. They are usually quantitative and can be measured, and are controlled by many genes (polygenic), such as height, weight, and skin colour in humans.</div>", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS"}, {"id": "objective>Biology>2002>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">N</span> is the dominant allele for normal vision and X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">n</span> the recessive allele for colour-blindness, a boy with the genotype YX<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">n</span> will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Have normal vision</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Be colour-blind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Be totally blind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Be a carrier of colour-blindness</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A boy with the genotype YX<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">n</span> will be colour-blind. In this case, X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">N</span> is the dominant allele for normal vision and X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">n</span> is the recessive allele for colour-blindness. Since males have only one X chromosome, they will express the trait associated with the allele they inherit, regardless of whether it is dominant or recessive. In this case, the boy has inherited the X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">n</span> allele, so he will be colour-blind.</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>2002>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first four children of a couple were all girls. The probability that the fifth will also be a girl is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1/5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/2</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gender of a baby is determined by the sex chromosomes that it inherits from its parents. A baby girl is formed when two X chromosomes are inherited (one from the mother and one from the father), while a baby boy is formed when an X and a Y chromosome are inherited (X from the mother and Y from the father). Since the mother can only pass on an X chromosome, the gender of the baby is determined by the father. If the father passes on an X chromosome, the baby will be a girl, and if he passes on a Y chromosome, the baby will be a boy. Therefore, the probability that a baby will be a girl is always 1/2, regardless of the genders of the previous children.</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>2002>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Genetic counseling is important when a marriage is planned between a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> woman and Rh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> man</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> woman and Rh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> man</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> woman and Rh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> man</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> woman and Rh <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> man</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rh factor is a protein found on red blood cells. People who have the Rh factor are Rh positive (Rh+) and those who do not are Rh negative (Rh-). Problems can occur during pregnancy if the mother is Rh- and the father is Rh+, because the baby could inherit the Rh+ factor from the father. This can lead to Rh disease, a condition where the mother's immune system attacks the baby's red blood cells. Genetic counseling is important in such cases to understand the risks and manage the pregnancy appropriately.</div>", "topic": "HEREDITY : APPLICATION OF THE PRINCIPLES OF HEREDITY"}, {"id": "objective>Biology>2002>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What proportion of the offspring of a cross between two heterozygous parents will exhibit the recessive condition phenotypically?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4/4</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> 1 HH - Homozygous (Dominant) <br/> 2 Hh - Heterozygous  <br/> 1 hh - Homozygous (recessive) <br/> Total = 4 <br/> pr(Recessive)  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td></tr></table></div> <br/> In a cross between two heterozygous parents (Aa x Aa), the Punnett square shows that 1/4 of the offspring will be homozygous dominant (AA), 1/2 will be heterozygous (Aa), and 1/4 will be homozygous recessive (aa). The homozygous recessive condition is the one that exhibits the recessive phenotype, so the proportion of offspring that will exhibit the recessive condition phenotypically is 1/4.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}];
